import{_ as t,o,c as a,a2 as i}from"./chunks/framework.CKCxdkvf.js";const h=JSON.parse('{"title":"ADR-025 — Accessibility tier-1 contract","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-025.md","filePath":"adr/ADR-025.md"}'),s={name:"adr/ADR-025.md"};function n(r,e,l,c,d,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-025-—-accessibility-tier-1-contract" tabindex="-1">ADR-025 — Accessibility tier-1 contract <a class="header-anchor" href="#adr-025-—-accessibility-tier-1-contract" aria-label="Permalink to &quot;ADR-025 — Accessibility tier-1 contract&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-29 Closes · RFC-005 (accessibility approach) TA anchor · §constraints · §components</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>RFC-005 raised the question: four of six screens render primarily to canvas or WebGL, which is inherently opaque to screen readers. What level of accessibility ships in v1, and where does v1 draw the line?</p><p>The answers needed locking before v0.1.0 because every contributor was making ad-hoc decisions (Slice 3 added some ARIA on /explore, Slice 4 added different ARIA on /fly, Slice 5 used yet another pattern on /moon). This ADR consolidates and locks the contract.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="tier-1-—-what-ships-in-v1" tabindex="-1">Tier 1 — what ships in v1 <a class="header-anchor" href="#tier-1-—-what-ships-in-v1" aria-label="Permalink to &quot;Tier 1 — what ships in v1&quot;">​</a></h3><p><strong>Reduced motion.</strong> All canvas screens detect <code>prefers-reduced-motion: reduce</code> via <code>matchMedia</code> (helper: <code>src/lib/reduced-motion.ts</code>) and stop <em>unsolicited</em> motion: /explore freezes simT, /fly defaults isPlaying=false, /moon stops auto-rotate. User-initiated motion (drag-to-orbit, scrub, scroll, click) still works. The contract is &quot;stop motion the user didn&#39;t ask for&quot;, not &quot;freeze the screen&quot;.</p><p><strong>Nav bar.</strong> <code>&lt;nav aria-label={m.nav_aria_label()}&gt;</code> (Svelte&#39;s a11y rule rejects redundant <code>role=&quot;navigation&quot;</code> on <code>&lt;nav&gt;</code>). All six links are real anchors so SvelteKit&#39;s router handles keyboard activation natively. The <code>:focus-visible</code> outline (2px brand-blue at 2px offset) is set globally on every interactive element via the design tokens.</p><p><strong>Detail panels.</strong> <code>Panel.svelte</code> is <code>&lt;aside&gt;</code> with <code>aria-label={title}</code> (implicit role=complementary, intentionally not role=dialog because panels don&#39;t trap focus from the underlying canvas — the user can still drag/scroll the scene with a panel open). On open, focus moves to the close button via <code>queueMicrotask</code>; on close, focus returns to whatever was active before. Escape closes the panel.</p><p><strong>Tab strips.</strong> Every panel tab strip (PlanetPanel, SunPanel, MissionPanel) implements the WAI-ARIA tabs pattern: <code>role=&quot;tablist&quot;</code> wrapping <code>role=&quot;tab&quot;</code> buttons with <code>aria-selected</code>, <code>aria-controls</code> linking to the tabpanel <code>id</code>, and the content area is <code>role=&quot;tabpanel&quot;</code> with <code>aria-labelledby</code> linked back to the active tab&#39;s id.</p><p><strong>Filter pills.</strong> /missions filter bar uses <code>role=&quot;radiogroup&quot;</code> per filter group, <code>role=&quot;radio&quot;</code> per pill, <code>aria-checked</code> reflecting active state — keyboard navigates with the native radio-button arrow-key behaviour.</p><p><strong>Canvas screens.</strong> Every canvas (3D and 2D) carries an honest <code>aria-label</code> describing what it shows and how to access details: e.g., /explore&#39;s 2D canvas reads &quot;2D top-down solar system. Drag to pan, scroll or pinch to zoom, tap planets and Sun for details.&quot; Tier 1 doesn&#39;t pretend the canvas is keyboard-navigable — it directs users to the panel.</p><p><strong>Live regions.</strong> The /explore hover tooltip is <code>role=&quot;status&quot; aria-live=&quot;polite&quot;</code> so screen readers announce orbital data on hover. /fly&#39;s identity HUD is <code>role=&quot;status&quot; aria-live=&quot;polite&quot;</code> for phase changes. /missions and /fly load-failure banners are <code>role=&quot;alert&quot;</code> for immediate announcement.</p><p><strong>Touch targets.</strong> 44 × 44 px minimum on every interactive element. /earth uses an &quot;invisible expanded hit pad&quot; pattern (4–6 px visual dot, 22 px hit radius) so dense diagrams remain tappable.</p><h3 id="tier-2-—-explicitly-deferred-to-v2" tabindex="-1">Tier 2 — explicitly deferred to v2 <a class="header-anchor" href="#tier-2-—-explicitly-deferred-to-v2" aria-label="Permalink to &quot;Tier 2 — explicitly deferred to v2&quot;">​</a></h3><p>Per RFC-005&#39;s tiered scope:</p><ul><li><strong>Canvas object keyboard navigation.</strong> Tabbing between planets/missions/sites within a canvas. Requires either a parallel DOM mirror (each clickable object as a hidden <code>&lt;button&gt;</code> overlaid on its canvas position) or porting to SVG. Both rewrite the rendering architecture; neither is justified for v1.</li><li><strong>Full screen-reader description of canvas content.</strong> The aria-label says &quot;click planets for details&quot;, which is honest. Reading every planet&#39;s position aloud is out of scope.</li><li><strong>High-contrast mode.</strong> Design system uses dark-on-dark with brand-blue accents — likely fails WCAG 2.1 AA contrast ratios in some places. v2 would require a token-level audit.</li><li><strong>Locales other than English.</strong> Paraglide-js + locale overlays are wired in (110 schema-validated files); adding fr, es, etc. is a content task, not a code task.</li><li><strong>PWA manifest + service worker.</strong></li></ul><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Tier 1 covers the user populations most blocked by canvas-heavy SPAs — keyboard-only and reduced-motion users. They can navigate the entire app, hear what every screen offers, and access the educational content via panels. Tier 2 is deferred not because it doesn&#39;t matter but because doing it right requires architectural changes (parallel DOM, SVG migration, token audit) that don&#39;t fit v1&#39;s &quot;ship the prototype&quot; scope.</p><p>The reduced-motion contract is the load-bearing piece. Auto-orbit on /explore + auto-play on /fly + auto-rotate on /moon would be nausea-inducing for vestibular-disorder users. Stopping these on demand — without disabling the screens — is the correct accessibility move.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Cover everything in v1 (delay ship).</strong> Would slip v0.1.0 by ≥ 2 slices for canvas-keyboard nav alone; no return on the delay because canvas-nav requires the SVG migration anyway.</li><li><strong>Skip accessibility entirely.</strong> Rejected — vestibular disorders affect ~3% of users; skipping reduced-motion is hostile.</li><li><strong>Use ARIA-live regions to read every canvas update.</strong> Tested informally; produces overwhelming announcements. Would need an audio-cue grammar that&#39;s its own design problem.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: keyboard-only and reduced-motion users have a clean v1 experience. Every interactive element has a visible focus indicator + 44 px hit pad. Live regions announce dynamic data without flooding.</p><p>Negative: screen-reader users still can&#39;t tab between objects within a canvas — they navigate via panels. Tier 2 work is real and tracked.</p><h2 id="validation-closing-evidence" tabindex="-1">Validation (closing evidence) <a class="header-anchor" href="#validation-closing-evidence" aria-label="Permalink to &quot;Validation (closing evidence)&quot;">​</a></h2><ul><li><code>prefers-reduced-motion</code> honoured on /explore, /fly, /moon — verified manually with macOS System Settings → Accessibility → Display → Reduce motion.</li><li>Every canvas carries <code>aria-label</code> (verified: <code>grep -rn &#39;aria-label&#39; src/routes</code> returns matches in all four canvas screens).</li><li>Every panel tab strip has matching <code>role=tablist/tab/tabpanel</code> (verified: PlanetPanel, SunPanel, MissionPanel all carry the pattern).</li><li>Every <code>&lt;aside class=&quot;panel&quot;&gt;</code> is wrapped in <code>aria-label={title}</code>; close-button focus management is tested in <code>tests/e2e/explore.spec.ts</code> (&quot;toggle stays accessible when panel is open&quot;).</li><li><code>:focus-visible</code> outline is set globally in <code>src/lib/styles/tokens.css</code> and overridden in component CSS only to brand colours, never <code>outline: none</code>.</li><li>44 × 44 px touch targets verified across speed pills (/fly), play button (/fly), 2D/3D toggles (/explore, /moon), CAPCOM toggle (/fly), filter pills (/missions).</li></ul>',28)])])}const v=t(s,[["render",n]]);export{h as __pageData,v as default};
